.darma-loader-darma-custom-733 {
  color: var(--loader-color, #ec4899);
width: 15px;
aspect-ratio: 1;
position: relative;
}
.darma-loader-darma-custom-733::before,
.darma-loader-darma-custom-733::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
background: currentColor;
}
.darma-loader-darma-custom-733::before {
box-shadow: -25px 0;
animation: darma-loader-darma-custom-733-l8-1 1s infinite linear;
}
.darma-loader-darma-custom-733::after {
transform: rotate(0deg) translateX(25px);
animation: darma-loader-darma-custom-733-l8-2 1s infinite linear;
}

@keyframes darma-loader-darma-custom-733-l8-1 {
100%{transform: translateX(25px)}
}
@keyframes darma-loader-darma-custom-733-l8-2 {
100%{transform: rotate(-180deg) translateX(25px)}
}

